            direction =
              mouseinfo.row < repeatinfo.mouseinfo.row
                ? 'left'
                : mouseinfo.row > repeatinfo.mouseinfo.row
                  ? 'right'
                  : '';
            repeatinfo.repeatcallback(coord, direction);
