    sectioninfo = thisformat.sectioninfo[section];
    sectioninfo.sectionstart = 0;
    sectioninfo.integerdigits = 0;
    sectioninfo.fractiondigits = 0;
    sectioninfo.commas = 0;
    sectioninfo.percent = 0;
