      if (ampmstr) {
        ampmstr += ch;
        part = ampmstr.toLowerCase();
        if (part == 'am/pm' || part == 'a/p') {
          thisformat.operators.push(scfn.commands.date);
          thisformat.operands.push(ampmstr);
          ampmstr = '';
        }
        continue;
      }
