  FormatNumberMut.convert_date_julian_to_gregorian = function (juliandate) {
    var L, N, I, J, K;
    L = juliandate + 68569;
    N = Math.floor((4 * L) / 146097);
    L = L - Math.floor((146097 * N + 3) / 4);
    I = Math.floor((4e3 * (L + 1)) / 1461001);
    L = L - Math.floor((1461 * I) / 4) + 31;
    J = Math.floor((80 * L) / 2447);
    K = L - Math.floor((2447 * J) / 80);
    L = Math.floor(J / 11);
    J = J + 2 - 12 * L;
    I = 100 * (N - 49) + I + L;
    return {
      year: I,
      month: J,
      day: K,
    };
  };
  SocialCalc.intFunc = function (n) {
    if (n < 0) {
      return -Math.floor(-n);
    } else {
      return Math.floor(n);
    }
  };

